// types.ts
export interface Invoice { id: string; number: string; customer: string; issuedAt: number; dueAt: number; amountCents: number; currency: string; status: 'paid' | 'unpaid' | 'overdue' | 'draft'; }

// formatCurrency.ts
export function formatCurrency(cents: number, currency = 'USD'): { integer: string; fraction: string; symbol: string } {
  const symbol = currency === 'USD' ? '$' : currency === 'EUR' ? '\u20AC' : currency;
  const totalDollars = cents / 100;
  const integer = Math.floor(totalDollars).toLocaleString('en-US');
  const fraction = String(Math.abs(cents) % 100).padStart(2, '0');
  return { integer, fraction, symbol };
}

// Amount.tsx — decimal-aligned currency display
export function Amount({ cents, currency = 'USD' }: { cents: number; currency?: string }) {
  const { integer, fraction, symbol } = formatCurrency(cents, currency);
  return (
    <span className="font-mono tabular-nums text-[13px]">
      <span className="text-[oklch(0.55_0.005_250)] mr-0.5">{symbol}</span>
      <span className="inline-block text-right" style={{ minWidth: '6ch' }}>{integer}</span>
      <span className="opacity-60">.</span>
      <span className="inline-block text-left" style={{ minWidth: '2ch' }}>{fraction}</span>
    </span>
  );
}

