import { useMemo, useState } from 'react';
import type { Invoice } from './types';
import { Amount } from './Amount';

interface Props { invoices: ReadonlyArray<Invoice>; }

export function InvoiceList({ invoices }: Props) {
  const [statusFilter, setStatusFilter] = useState<Invoice['status'] | 'all'>('all');
  const [selected, setSelected] = useState<Set<string>>(new Set());
  const [hovered, setHovered] = useState<string | null>(null);

  const visible = useMemo(() => statusFilter === 'all' ? invoices : invoices.filter(i => i.status === statusFilter), [invoices, statusFilter]);

  const aggregateRows = selected.size > 0 ? visible.filter(i => selected.has(i.id)) : visible;
  const sum = aggregateRows.reduce((s, i) => s + i.amountCents, 0);
  const avgDaysOutstanding = aggregateRows.length > 0 ? aggregateRows.reduce((s, i) => s + Math.max(0, (Date.now() - i.dueAt) / 86400000), 0) / aggregateRows.length : 0;

  return (
    <div className="relative">
      <div className="flex gap-2 p-3 border-b border-[oklch(0.93_0.005_250)]">
        {(['all','paid','unpaid','overdue','draft'] as const).map(s => (
          <button key={s} type="button" onClick={() => setStatusFilter(s)} className={`px-2.5 py-1 text-[11px] uppercase tracking-wider rounded ${statusFilter === s ? 'bg-[oklch(0.2_0.01_250)] text-white' : 'text-[oklch(0.55_0.005_250)] hover:bg-[oklch(0.94_0.005_250)]'}`}>{s}</button>
        ))}
      </div>
      <table className="w-full border-collapse text-[13px]">
        <thead>
          <tr>
            {['Invoice','Customer','Issued','Due','Amount','Status'].map(h => <th key={h} className="text-left text-[11px] uppercase tracking-wider font-semibold px-3 py-2 text-[oklch(0.55_0.005_250)] border-b border-[oklch(0.92_0.005_250)]">{h}</th>)}
          </tr>
        </thead>
        <tbody>
          {visible.map(inv => {
            const isSelected = selected.has(inv.id);
            return (
              <tr key={inv.id} onMouseEnter={() => setHovered(inv.id)} onMouseLeave={() => setHovered(null)} onClick={(e) => { if (e.shiftKey) setSelected(s => { const n = new Set(s); if (n.has(inv.id)) n.delete(inv.id); else n.add(inv.id); return n; }); }}
                className={`cursor-pointer ${isSelected ? 'bg-[oklch(0.96_0.04_250)]' : hovered === inv.id ? 'bg-[oklch(0.97_0.005_250)]' : ''}`}>
                <td className="px-3 py-2 font-mono text-[12px] tabular-nums">{inv.number}</td>
                <td className="px-3 py-2 truncate max-w-[200px]">{inv.customer}</td>
                <td className="px-3 py-2 tabular-nums text-[oklch(0.55_0.005_250)]">{new Date(inv.issuedAt).toLocaleDateString()}</td>
                <td className="px-3 py-2 tabular-nums text-[oklch(0.55_0.005_250)]">{new Date(inv.dueAt).toLocaleDateString()}</td>
                <td className="px-3 py-2 text-right"><Amount cents={inv.amountCents} currency={inv.currency} /></td>
                <td className="px-3 py-2"><StatusChip status={inv.status} /></td>
              </tr>
            );
          })}
        </tbody>
      </table>
      <footer className="sticky bottom-0 bg-[oklch(0.97_0.005_250)] border-t border-[oklch(0.92_0.005_250)] flex items-center px-3 h-12" role="status" aria-live="polite">
        <span className="text-[12px] text-[oklch(0.55_0.005_250)] mr-auto">{selected.size > 0 ? `${selected.size} selected of ` : ''}{visible.length} invoice{visible.length === 1 ? '' : 's'}{statusFilter !== 'all' ? ` \u00B7 ${statusFilter}` : ''}</span>
        <div className="flex gap-8">
          <div><span className="text-[11px] uppercase tracking-wider text-[oklch(0.55_0.005_250)] block">Avg days outstanding</span><span className="text-[14px] tabular-nums font-mono">{avgDaysOutstanding.toFixed(1)}</span></div>
          <div><span className="text-[11px] uppercase tracking-wider text-[oklch(0.55_0.005_250)] block">Total</span><Amount cents={sum} /></div>
        </div>
      </footer>
    </div>
  );
}

function StatusChip({ status }: { status: Invoice['status'] }) {
  const styles: Record<Invoice['status'], { bg: string; text: string }> = {
    paid: { bg: 'oklch(0.94 0.06 145)', text: 'oklch(0.4 0.14 145)' },
    unpaid: { bg: 'oklch(0.95 0.04 250)', text: 'oklch(0.35 0.1 250)' },
    overdue: { bg: 'oklch(0.94 0.08 25)', text: 'oklch(0.4 0.16 25)' },
    draft: { bg: 'oklch(0.93 0.005 250)', text: 'oklch(0.45 0.005 250)' },
  };
  const s = styles[status];
  return <span className="px-1.5 py-0.5 text-[11px] uppercase tracking-wider rounded" style={{ background: s.bg, color: s.text }}>{status}</span>;
}

// types.ts
export type BlockNode = { kind: 'p' | 'h1' | 'h2' | 'h3'; text: string } | { kind: 'list'; ordered: boolean; items: string[] } | { kind: 'code'; lang: string; code: string } | { kind: 'quote'; text: string };

// parse.ts (simplified — full markdown parser is out of scope)
export function parseBlocks(raw: string): BlockNode[] {
  return raw.split(/\n\n+/).map(chunk => {
    if (chunk.startsWith('# ')) return { kind: 'h1' as const, text: chunk.slice(2) };
    if (chunk.startsWith('## ')) return { kind: 'h2' as const, text: chunk.slice(3) };
    if (chunk.startsWith('### ')) return { kind: 'h3' as const, text: chunk.slice(4) };
    if (chunk.startsWith('> ')) return { kind: 'quote' as const, text: chunk.slice(2) };
    if (chunk.startsWith('```')) {
      const [first, ...rest] = chunk.split('\n');
      return { kind: 'code' as const, lang: first.slice(3).trim(), code: rest.slice(0, -1).join('\n') };
    }
    if (/^[-*] /.test(chunk)) return { kind: 'list' as const, ordered: false, items: chunk.split('\n').map(l => l.replace(/^[-*] /, '')) };
    if (/^\d+\. /.test(chunk)) return { kind: 'list' as const, ordered: true, items: chunk.split('\n').map(l => l.replace(/^\d+\. /, '')) };
    return { kind: 'p' as const, text: chunk };
  });
}

export function blockToRaw(b: BlockNode): string {
  switch (b.kind) {
    case 'h1': return `# ${b.text}`;
    case 'h2': return `## ${b.text}`;
    case 'h3': return `### ${b.text}`;
    case 'p': return b.text;
    case 'quote': return `> ${b.text}`;
    case 'code': return `\`\`\`${b.lang}\n${b.code}\n\`\`\``;
    case 'list': return b.items.map((i, idx) => `${b.ordered ? `${idx + 1}.` : '-'} ${i}`).join('\n');
  }
}

// MarkdownEditor.tsx
import { useEffect, useState } from 'react';
import { parseBlocks, blockToRaw, type BlockNode } from './parse';

interface Props { initialMarkdown: string; onChange: (md: string) => void; }

export function MarkdownEditor({ initialMarkdown, onChange }: Props) {
  const [blocks, setBlocks] = useState<BlockNode[]>(() => parseBlocks(initialMarkdown));
  const [cursorBlockIdx, setCursorBlockIdx] = useState<number | null>(null);
  const [rawMode, setRawMode] = useState(false);

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key === 'M') { e.preventDefault(); setRawMode(r => !r); }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, []);

  if (rawMode) {
    return <textarea value={blocks.map(blockToRaw).join('\n\n')} onChange={(e) => { const next = parseBlocks(e.target.value); setBlocks(next); onChange(e.target.value); }} className="w-full h-screen p-8 font-mono text-[15px] outline-none resize-none bg-[oklch(0.99_0.003_80)]" />;
  }

  return (
    <div className="max-w-[720px] mx-auto py-8 px-4">
      {blocks.map((b, i) => (
        <Block key={i} block={b} isCursorInside={cursorBlockIdx === i} onFocus={() => setCursorBlockIdx(i)} onBlur={() => setCursorBlockIdx(c => c === i ? null : c)} onChange={(newBlock) => { setBlocks(bs => bs.map((bb, j) => j === i ? newBlock : bb)); onChange(blocks.map(blockToRaw).join('\n\n')); }} />
      ))}
    </div>
  );
}

function Block({ block, isCursorInside, onFocus, onBlur, onChange }: { block: BlockNode; isCursorInside: boolean; onFocus: () => void; onBlur: () => void; onChange: (b: BlockNode) => void }) {
  // When cursor is inside, render raw textarea-like editing
  // When outside, render styled
  if (isCursorInside) {
    return (
      <div tabIndex={0} onFocus={onFocus} onBlur={onBlur} contentEditable suppressContentEditableWarning className="font-mono text-[15px] my-2 outline-none whitespace-pre-wrap" onInput={(e) => {
        const text = (e.target as HTMLElement).innerText;
        // re-parse this block from text
        const parsed = parseBlocks(text)[0];
        if (parsed) onChange(parsed);
      }}>{blockToRaw(block)}</div>
    );
  }
  return <RenderedBlock block={block} onFocus={onFocus} />;
}

function RenderedBlock({ block, onFocus }: { block: BlockNode; onFocus: () => void }) {
  const baseProps = { tabIndex: 0, onFocus, className: 'outline-none focus-visible:outline focus-visible:outline-1 focus-visible:outline-[oklch(0.55_0.18_250)] my-2' };
  switch (block.kind) {
    case 'h1': return <h1 {...baseProps} className={baseProps.className + ' text-[28px] font-medium leading-[36px]'}>{block.text}</h1>;
    case 'h2': return <h2 {...baseProps} className={baseProps.className + ' text-[22px] font-medium leading-[30px]'}>{block.text}</h2>;
    case 'h3': return <h3 {...baseProps} className={baseProps.className + ' text-[18px] font-medium leading-[26px]'}>{block.text}</h3>;
    case 'quote': return <blockquote {...baseProps} className={baseProps.className + ' border-l-2 border-[oklch(0.85_0.005_60)] pl-4 italic text-[oklch(0.45_0.005_60)]'}>{block.text}</blockquote>;
    case 'code': return <pre {...baseProps} className={baseProps.className + ' bg-[oklch(0.95_0.005_60)] p-3 rounded font-mono text-[13px]'}>{block.code}</pre>;
    case 'list': {
      const Tag = block.ordered ? 'ol' : 'ul';
      return <Tag {...baseProps}>{block.items.map((item, i) => <li key={i}>{item}</li>)}</Tag>;
    }
    case 'p': default: return <p {...baseProps} className={baseProps.className + ' text-[17px] leading-[28px]'}>{block.text}</p>;
  }
}

// types.ts
export interface Heading { id: string; level: 1 | 2 | 3; text: string; topOffset: number; bottomOffset: number; }
export interface UserReadingPos { userId: string; userName: string; colorIdx: number; scrollY: number; }

// useReadingPosition.ts
import { useMemo } from 'react';
import type { Heading, UserReadingPos } from './types';
export function useReadingPositions(headings: ReadonlyArray<Heading>, users: ReadonlyArray<UserReadingPos>): Map<string, UserReadingPos[]> {
  return useMemo(() => {
    const map = new Map<string, UserReadingPos[]>();
    for (const u of users) {
      const heading = headings.find(h => u.scrollY >= h.topOffset && u.scrollY < h.bottomOffset);
      if (!heading) continue;
      if (!map.has(heading.id)) map.set(heading.id, []);
      map.get(heading.id)!.push(u);
    }
    return map;
  }, [headings, users]);
}

