                <button type="button" onClick={() => onScrollTo(h.topOffset)} className={`text-[13px] flex-1 text-left truncate ${isCurrent ? 'font-medium text-[oklch(0.2_0.01_250)]' : 'text-[oklch(0.4_0.005_250)] hover:text-[oklch(0.2_0.01_250)]'}`}>{h.text}</button>
