                  {dots.slice(0, 4).map(u => (
                    <button key={u.userId} type="button" onClick={() => setFollowingId(u.userId)} aria-label={`Follow ${u.userName}`} className="w-2 h-2 rounded-full ring-1 ring-white" style={{ background: PALETTE[u.colorIdx % PALETTE.length] }} title={u.userName} />
