// useDragReorder.ts
import { useCallback, useRef, useState } from 'react';

interface Options<T> { items: ReadonlyArray<T>; onReorder: (next: ReadonlyArray<T>) => void; rowHeight: number; getId: (item: T) => string; }

export function useDragReorder<T>({ items, onReorder, rowHeight, getId }: Options<T>) {
  const [draggingId, setDraggingId] = useState<string | null>(null);
  const [dragY, setDragY] = useState(0);
  const dragStartY = useRef(0);
  const originalIdx = useRef(0);

  const targetIdx = draggingId ? Math.max(0, Math.min(items.length - 1, originalIdx.current + Math.round(dragY / rowHeight))) : -1;

  const onPointerDown = useCallback((id: string, e: React.PointerEvent) => {
    setDraggingId(id);
    dragStartY.current = e.clientY;
    setDragY(0);
    originalIdx.current = items.findIndex(i => getId(i) === id);
    (e.target as Element).setPointerCapture(e.pointerId);
  }, [items, getId]);

  const onPointerMove = useCallback((e: React.PointerEvent) => {
    if (!draggingId) return;
    setDragY(e.clientY - dragStartY.current);
  }, [draggingId]);

  const onPointerUp = useCallback(() => {
    if (!draggingId) return;
    const newIdx = targetIdx;
    if (newIdx !== originalIdx.current) {
      const arr = items.slice();
      const [moved] = arr.splice(originalIdx.current, 1);
      arr.splice(newIdx, 0, moved);
      onReorder(arr);
      if ('vibrate' in navigator) navigator.vibrate(8);
    }
    setDraggingId(null);
    setDragY(0);
  }, [draggingId, targetIdx, items, onReorder]);

  const onCancel = useCallback(() => { setDraggingId(null); setDragY(0); }, []);

  // offset for each row given drag state
  const offsetFor = useCallback((idx: number): number => {
    if (!draggingId) return 0;
    if (idx === originalIdx.current) return dragY;
    if (originalIdx.current < targetIdx && idx > originalIdx.current && idx <= targetIdx) return -rowHeight;
    if (originalIdx.current > targetIdx && idx < originalIdx.current && idx >= targetIdx) return rowHeight;
    return 0;
  }, [draggingId, dragY, targetIdx, rowHeight]);

  return { draggingId, offsetFor, onPointerDown, onPointerMove, onPointerUp, onCancel };
}

// SortableList.tsx
import { useEffect } from 'react';
import { useDragReorder } from './useDragReorder';

interface BaseItem { id: string; }
interface Props<T extends BaseItem> { items: ReadonlyArray<T>; renderItem: (item: T) => React.ReactNode; onReorder: (next: ReadonlyArray<T>) => void; }

export function SortableList<T extends BaseItem>({ items, renderItem, onReorder }: Props<T>) {
  const d = useDragReorder({ items, onReorder, rowHeight: 44, getId: (i) => i.id });
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => { if (e.key === 'Escape') d.onCancel(); };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [d]);

  return (
    <ul role="list" className="select-none">
      {items.map((item, i) => {
        const isDragging = item.id === d.draggingId;
        const offset = d.offsetFor(i);
        return (
          <li key={item.id} role="listitem"
            className={`flex items-center h-11 px-3 bg-white ${isDragging ? 'shadow-lg z-10' : ''}`}
            style={{ transform: `translateY(${offset}px) ${isDragging ? 'scale(1.02)' : 'scale(1)'}`, transition: isDragging ? 'none' : 'transform 200ms ease-out, box-shadow 200ms ease-out', boxShadow: isDragging ? '0 8px 24px oklch(0.18 0.005 250 / 0.15)' : 'none' }}>
            <button type="button"
              onPointerDown={(e) => d.onPointerDown(item.id, e)}
              onPointerMove={d.onPointerMove}
              onPointerUp={d.onPointerUp}
              aria-label="Drag to reorder"
              className="w-4 h-4 mr-3 text-[oklch(0.85_0.005_250)] hover:text-[oklch(0.55_0.005_250)] cursor-grab active:cursor-grabbing touch-none">\u2807</button>
            <div className="flex-1">{renderItem(item)}</div>
          </li>
        );
      })}
    </ul>
  );
}

// DiffChart.tsx
import { useState, useMemo } from 'react';
export interface SeriesPoint { t: number; v: number; }
export function DiffChart({ seriesA, seriesB, labels }: { seriesA: ReadonlyArray<SeriesPoint>; seriesB: ReadonlyArray<SeriesPoint>; labels: [string, string] }) {
  const W = 720, LANE_H = 120;
  const allT = [...seriesA, ...seriesB].map(p => p.t);
  const tMin = Math.min(...allT), tMax = Math.max(...allT);
  const xScale = (t: number) => ((t - tMin) / (tMax - tMin)) * W;
  const delta = useMemo(() => seriesA.map((a, i) => ({ t: a.t, v: (seriesB[i]?.v ?? 0) - a.v })), [seriesA, seriesB]);
  const dMax = Math.max(...delta.map(d => Math.abs(d.v))) || 1;
  const yScaleSeries = (v: number, max: number) => LANE_H - (v / max) * LANE_H;
  const aMax = Math.max(...seriesA.map(p => p.v)), bMax = Math.max(...seriesB.map(p => p.v));
  const [hoverT, setHoverT] = useState<number | null>(null);
  const pathFor = (data: ReadonlyArray<SeriesPoint>, max: number) => data.map((p, i) => `${i ? 'L' : 'M'}${xScale(p.t).toFixed(1)} ${yScaleSeries(p.v, max).toFixed(1)}`).join(' ');
  const deltaArea = delta.map((d, i) => `${i ? 'L' : 'M'}${xScale(d.t).toFixed(1)} ${(LANE_H/2 - (d.v / dMax) * LANE_H/2).toFixed(1)}`).join(' ') + ` L${W} ${LANE_H/2} L0 ${LANE_H/2} Z`;
  return (
    <div onMouseLeave={() => setHoverT(null)} onMouseMove={(e) => { const r = (e.currentTarget as HTMLDivElement).getBoundingClientRect(); setHoverT(tMin + ((e.clientX - r.left) / r.width) * (tMax - tMin)); }}>
      <Lane title={labels[0]} height={LANE_H}><path d={pathFor(seriesA, aMax)} stroke="oklch(0.55 0.18 250)" strokeWidth="1.5" fill="none" /></Lane>
      <Lane title={labels[1]} height={LANE_H}><path d={pathFor(seriesB, bMax)} stroke="oklch(0.55 0.16 25)" strokeWidth="1.5" fill="none" /></Lane>
      <Lane title="Delta (B - A)" height={LANE_H}>
        <line x1={0} y1={LANE_H/2} x2={W} y2={LANE_H/2} stroke="oklch(0.5 0.005 250)" strokeDasharray="2 2" />
        <path d={deltaArea} fill="oklch(0.55 0.14 145 / 0.3)" />
      </Lane>
    </div>
  );
}
function Lane({ title, height, children }: { title: string; height: number; children: React.ReactNode }) {
  return (<div><div className="text-[11px] uppercase tracking-wider text-[oklch(0.55_0.005_250)] mb-1">{title}</div><svg width={720} height={height} className="block">{children}</svg></div>);
}

// TemplateChooser.tsx
import { useState, useEffect } from 'react';
export interface Template { id: string; name: string; description: string; useCase: string; thumbnailUrl: string; previewScreenshotUrl: string; previewIframeUrl: string; }
export function TemplateChooser({ templates, onUseTemplate }: { templates: ReadonlyArray<Template>; onUseTemplate: (t: Template) => void }) {
  const [hoverId, setHoverId] = useState<string | null>(null);
  const [selectedId, setSelectedId] = useState<string | null>(null);
