// types.ts
export interface Question { id: string; prompt: string; type: 'text' | 'choice' | 'rating'; choices?: ReadonlyArray<string>; required: boolean; }
export type BranchFn = (answer: unknown, currentId: string, answers: Map<string, unknown>) => string | null;

// useSurveyPath.ts
import { useCallback, useState } from 'react';
export function useSurveyPath(questions: ReadonlyArray<Question>, branch: BranchFn, startId: string) {
  const [path, setPath] = useState<string[]>([startId]);
  const [answers, setAnswers] = useState<Map<string, unknown>>(new Map());
  const currentId = path[path.length - 1];
  const current = questions.find(q => q.id === currentId)!;
  const next = useCallback((answer: unknown) => {
    const newAnswers = new Map(answers); newAnswers.set(currentId, answer);
    const nextId = branch(answer, currentId, newAnswers);
    setAnswers(newAnswers);
    if (nextId) setPath(p => [...p, nextId]);
  }, [answers, currentId, branch]);
  const back = useCallback(() => { setPath(p => p.length > 1 ? p.slice(0, -1) : p); }, []);
  const jumpTo = useCallback((id: string) => { const idx = path.indexOf(id); if (idx >= 0) setPath(p => p.slice(0, idx + 1)); }, [path]);
  return { current, path, answers, next, back, jumpTo };
}

