import { useMemo } from 'react';
import { CatmullRomCurve3, Vector3 } from 'three';
import { Html } from '@react-three/drei';
export interface TimelineEvent { id: string; year: number; title: string; body: string; }
export function CurvedCardPath({ events }: { events: ReadonlyArray<TimelineEvent> }) {
  const sorted = useMemo(() => [...events].sort((a, b) => a.year - b.year), [events]);
  const curve = useMemo(() => new CatmullRomCurve3(sorted.map((_, i) => new Vector3(Math.sin(i * 0.4) * 4, i * 0.6 - sorted.length * 0.3, -i * 2))), [sorted]);
  return (<>{sorted.map((e, i) => { const pos = curve.getPoint(i / Math.max(1, sorted.length - 1)); return (
    <group key={e.id} position={[pos.x, pos.y, pos.z]} rotation={[0.1, -0.2, 0]}>
      <mesh><planeGeometry args={[2.4, 1.8]} /><meshStandardMaterial color="oklch(0.99 0.005 250)" /></mesh>
      <Html center distanceFactor={6} transform style={{ pointerEvents: 'none' }}>
        <div className="w-[200px] text-[oklch(0.18_0.005_250)] p-3">
          <div className="text-[11px] font-mono tabular-nums text-[oklch(0.55_0.005_250)]">{e.year}</div>
          <div className="text-[16px] font-serif mt-1">{e.title}</div>
          <p className="text-[12px] mt-2 leading-[18px]">{e.body}</p>
        </div>
      </Html>
    </group>);
  })}</>);
}
