// AnnouncerContext.tsx
import { createContext, useContext, useRef, useState, useEffect } from 'react';
interface Ctx { announce: (msg: string, urgency?: 'polite' | 'assertive') => void; }
const C = createContext<Ctx | null>(null);
export function AnnouncerProvider({ children }: { children: React.ReactNode }) {
  const [polite, setPolite] = useState('');
  const [assertive, setAssertive] = useState('');
  const recent = useRef<Map<string, number>>(new Map());
  const lastAssertive = useRef(0);
  const politePending = useRef<string[]>([]);
  const politeTimer = useRef<number | null>(null);
  const announce = (msg: string, urgency: 'polite' | 'assertive' = 'polite') => {
    const now = Date.now();
    const lastTs = recent.current.get(msg);
    if (lastTs && now - lastTs < 1000) return;
    recent.current.set(msg, now);
    if (urgency === 'assertive') {
      if (now - lastAssertive.current < 2000) return;
      lastAssertive.current = now;
      setAssertive(msg);
      return;
    }
    politePending.current.push(msg);
    if (politeTimer.current) window.clearTimeout(politeTimer.current);
    politeTimer.current = window.setTimeout(() => {
      const msgs = politePending.current;
      politePending.current = [];
      setPolite(msgs.length > 1 && msgs.every(m => m === msgs[0]) ? `${msgs[0]} (${msgs.length} times)` : msgs.join('. '));
    }, 300);
  };
  useEffect(() => () => { if (politeTimer.current) window.clearTimeout(politeTimer.current); }, []);
  return (
    <C.Provider value={{ announce }}>{children}
      <div role="status" aria-live="polite" aria-atomic="true" className="sr-only">{polite}</div>
      <div role="alert" aria-live="assertive" aria-atomic="true" className="sr-only">{assertive}</div>
    </C.Provider>
  );
}
export const useAnnounce = () => { const v = useContext(C); if (!v) throw new Error('AnnouncerProvider missing'); return v.announce; };

// useOptimisticMutation.ts
import { useCallback, useState } from 'react';
export function useOptimisticMutation<T, R>(initial: T, server: (input: T) => Promise<R>) {
  const [value, setValue] = useState<T>(initial);
  const [pending, setPending] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [previousValue, setPreviousValue] = useState<T>(initial);
  const mutate = useCallback(async (next: T) => {
    setPreviousValue(value);
    setValue(next);
    setPending(true);
    setError(null);
    try { await server(next); setPending(false); }
    catch (e) { setValue(previousValue); setPending(false); setError((e as Error).message || 'Failed'); }
  }, [value, previousValue, server]);
  const retry = useCallback(() => mutate(value), [mutate, value]);
  const dismissError = useCallback(() => setError(null), []);
  return { value, pending, error, mutate, retry, dismissError };
}
