// useTabKeyboard.ts
import { useEffect } from 'react';
export function useTabKeyboard(opts: { onNew: () => void; onClose: () => void; onReopen: () => void; onJump: (n: number) => void; onNext: () => void; onPrev: () => void; }) {
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (!(e.metaKey || e.ctrlKey)) return;
      if (e.key === 't' && !e.shiftKey) { e.preventDefault(); opts.onNew(); }
      else if (e.key === 'w') { e.preventDefault(); opts.onClose(); }
      else if (e.key === 'T' && e.shiftKey) { e.preventDefault(); opts.onReopen(); }
      else if (e.key >= '1' && e.key <= '9') { e.preventDefault(); opts.onJump(parseInt(e.key, 10) - 1); }
      else if (e.key === ']') { e.preventDefault(); opts.onNext(); }
      else if (e.key === '[') { e.preventDefault(); opts.onPrev(); }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [opts]);
}
// useClosedStack.ts
import { useRef } from 'react';
export function useClosedStack<T>(max = 10) {
  const stack = useRef<T[]>([]);
  return { push: (item: T) => { stack.current = [...stack.current.slice(-(max - 1)), item]; }, pop: (): T | undefined => stack.current.pop() };
}
