// ToastProvider.tsx
import { createContext, useContext, useState, useCallback, useRef, useEffect } from 'react';
export interface Toast { id: string; title: string; description?: string; kind: 'success' | 'error' | 'info'; action?: { label: string; onClick: () => void }; duration?: number; }
interface Ctx { toast: (t: Omit<Toast, 'id'>) => void; }
const C = createContext<Ctx | null>(null);
export function ToastProvider({ children }: { children: React.ReactNode }) {
  const [toasts, setToasts] = useState<Toast[]>([]);
  const [paused, setPaused] = useState(false);
  const timers = useRef<Map<string, { remaining: number; lastStart: number }>>(new Map());
  const toast = useCallback((t: Omit<Toast, 'id'>) => {
    const id = crypto.randomUUID();
    setToasts(ts => [...ts.slice(-3), { ...t, id, duration: t.duration ?? 4000 }]);
    timers.current.set(id, { remaining: t.duration ?? 4000, lastStart: Date.now() });
  }, []);
  useEffect(() => {
    if (paused) {
      timers.current.forEach((v) => { v.remaining -= Date.now() - v.lastStart; });
      return;
    }
    timers.current.forEach((v, id) => {
      v.lastStart = Date.now();
      window.setTimeout(() => { if (!paused) setToasts(ts => ts.filter(t => t.id !== id)); timers.current.delete(id); }, v.remaining);
    });
  }, [paused]);
  return (
    <C.Provider value={{ toast }}>{children}
      <div className="fixed bottom-4 right-4 flex flex-col gap-2 z-50" onMouseEnter={() => setPaused(true)} onMouseLeave={() => setPaused(false)}>
        {toasts.map(t => (
          <div key={t.id} role="status" aria-live={t.kind === 'error' ? 'assertive' : 'polite'} className="w-80 bg-[oklch(0.18_0.005_250)] text-white rounded-md shadow-lg p-3 flex items-start gap-3" style={{ animation: 'toastIn 200ms cubic-bezier(0.22, 1, 0.36, 1)', borderLeft: `3px solid ${t.kind === 'success' ? 'oklch(0.55 0.14 145)' : t.kind === 'error' ? 'oklch(0.6 0.18 25)' : 'oklch(0.55 0.18 250)'}` }}>
