// StackedAreaChart.tsx
import { useState, useMemo } from 'react';
export interface AreaSeries { id: string; label: string; color: string; values: ReadonlyArray<number>; }
export function StackedAreaChart({ series, labels }: { series: ReadonlyArray<AreaSeries>; labels: ReadonlyArray<string> }) {
  const W = 480, H = 280;
  const N = labels.length;
  const [hoverId, setHoverId] = useState<string | null>(null);
  const [pinnedId, setPinnedId] = useState<string | null>(null);
  const isolated = pinnedId ?? hoverId;
  // compute cumulative stacks per index
  const stacks = useMemo(() => {
    const out: number[][] = labels.map(() => []);
    for (let i = 0; i < N; i++) {
      let acc = 0;
      for (const s of series) { out[i].push(acc); acc += s.values[i]; out[i].push(acc); }
    }
    return out;
  }, [series, labels, N]);
  const maxTotal = Math.max(...stacks.map(s => s[s.length - 1] || 0));
  const xScale = (i: number) => (i / (N - 1)) * W;
  const yScale = (v: number) => H - (v / maxTotal) * H;
  return (
    <div>
      <svg width={W} height={H}>
        {series.map((s, si) => {
          const dimmed = isolated && isolated !== s.id;
          const d = labels.map((_, i) => {
            const bot = stacks[i][si * 2];
            const top = stacks[i][si * 2 + 1];
            return { i, bot, top };
          });
          const path = `M${xScale(0)} ${yScale(d[0].top)}` + d.slice(1).map(p => `L${xScale(p.i)} ${yScale(p.top)}`).join('') + `L${xScale(N - 1)} ${yScale(d[N - 1].bot)}` + d.slice(0, -1).reverse().map(p => `L${xScale(p.i)} ${yScale(p.bot)}`).join('') + 'Z';
          return <path key={s.id} d={path} fill={s.color} style={{ opacity: dimmed ? 0.2 : 1, transition: 'opacity 150ms ease-out' }} onMouseEnter={() => setHoverId(s.id)} onMouseLeave={() => setHoverId(null)} onClick={() => setPinnedId(p => p === s.id ? null : s.id)} />;
        })}
      </svg>
      <div className="flex gap-3 mt-2 text-[12px]">
        {series.map(s => <button key={s.id} type="button" onMouseEnter={() => setHoverId(s.id)} onMouseLeave={() => setHoverId(null)} onClick={() => setPinnedId(p => p === s.id ? null : s.id)} className="flex items-center gap-1.5" style={{ opacity: isolated && isolated !== s.id ? 0.3 : 1 }}><span className="w-2 h-2 rounded" style={{ background: s.color }} />{s.label}{pinnedId === s.id && <span className="text-[10px] opacity-60">pinned</span>}</button>)}
      </div>
    </div>
  );
}

