// phoneFormat.ts (simplified — production uses libphonenumber)
export function formatPhone(digits: string, country: 'US' | 'GB' | 'FR' | 'DE' | 'IL'): string {
  const d = digits.replace(/\D/g, '');
  if (country === 'US') {
    if (d.length <= 3) return d;
    if (d.length <= 6) return `${d.slice(0,3)}-${d.slice(3)}`;
    return `${d.slice(0,3)}-${d.slice(3,6)}-${d.slice(6,10)}`;
  }
  if (country === 'GB') return `${d.slice(0,4)} ${d.slice(4,7)} ${d.slice(7,11)}`;
  return d;
}
export const COUNTRY_CODES: Record<string, { prefix: string; flag: string }> = {
  US: { prefix: '+1', flag: '\uD83C\uDDFA\uD83C\uDDF8' },
  GB: { prefix: '+44', flag: '\uD83C\uDDEC\uD83C\uDDE7' },
  FR: { prefix: '+33', flag: '\uD83C\uDDEB\uD83C\uDDF7' },
  DE: { prefix: '+49', flag: '\uD83C\uDDE9\uD83C\uDDEA' },
  IL: { prefix: '+972', flag: '\uD83C\uDDEE\uD83C\uDDF1' },
};
