// Combobox.tsx
import { useId, useRef, useState, useMemo } from 'react';
export interface ComboboxProps<T> { options: ReadonlyArray<T>; getLabel: (item: T) => string; getId: (item: T) => string; value: T | null; onChange: (item: T | null) => void; placeholder?: string; }
export function Combobox<T>({ options, getLabel, getId, value, onChange, placeholder }: ComboboxProps<T>) {
  const baseId = useId();
  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState(value ? getLabel(value) : '');
  const [focusIdx, setFocusIdx] = useState(0);
  const filtered = useMemo(() => { const q = query.toLowerCase(); return options.filter(o => getLabel(o).toLowerCase().includes(q)); }, [options, query, getLabel]);
  const select = (item: T) => { onChange(item); setQuery(getLabel(item)); setOpen(false); };
  return (
    <div className="relative">
      <input role="combobox" aria-expanded={open} aria-controls={`${baseId}-listbox`} aria-activedescendant={open && filtered[focusIdx] ? `${baseId}-opt-${getId(filtered[focusIdx])}` : undefined}
        value={query} onChange={(e) => { setQuery(e.target.value); setOpen(true); setFocusIdx(0); }} onFocus={() => setOpen(true)} onKeyDown={(e) => {
          if (e.key === 'ArrowDown') { e.preventDefault(); setOpen(true); setFocusIdx(i => Math.min(filtered.length - 1, i + 1)); }
          else if (e.key === 'ArrowUp') { e.preventDefault(); setFocusIdx(i => Math.max(0, i - 1)); }
          else if ((e.key === 'Enter' || e.key === 'Tab') && open && filtered[focusIdx]) { if (e.key === 'Enter') e.preventDefault(); select(filtered[focusIdx]); }
          else if (e.key === 'Escape') { setOpen(false); }
        }} placeholder={placeholder} className="w-full h-9 px-3 text-[14px] border border-[oklch(0.85_0.005_250)] rounded-md outline-none focus:border-[oklch(0.55_0.18_250)]" />
      {open && filtered.length > 0 && (
        <ul id={`${baseId}-listbox`} role="listbox" className="absolute top-full left-0 right-0 mt-1 max-h-[280px] overflow-y-auto bg-white rounded-md shadow-lg border border-[oklch(0.92_0.005_250)] z-10" style={{ animation: 'comboIn 80ms ease-out' }}>
          {filtered.map((opt, i) => <li key={getId(opt)} id={`${baseId}-opt-${getId(opt)}`} role="option" aria-selected={i === focusIdx} onMouseEnter={() => setFocusIdx(i)} onClick={() => select(opt)} className={`px-3 py-2 text-[13px] cursor-pointer ${i === focusIdx ? 'bg-[oklch(0.94_0.04_250)]' : 'hover:bg-[oklch(0.97_0.005_250)]'}`}>{getLabel(opt)}</li>)}
          <style>{`@keyframes comboIn { from { opacity: 0 } to { opacity: 1 } }`}</style>
        </ul>
      )}
    </div>
  );
}

