// useShortcutHelp.ts
import { useEffect, useState } from 'react';
export function useShortcutHelp() {
  const [open, setOpen] = useState(false);
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => { if (e.key === '?' && !(e.target instanceof HTMLInputElement)) { e.preventDefault(); setOpen(true); } if (e.key === 'Escape') setOpen(false); };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, []);
  return { open, close: () => setOpen(false) };
}
export interface Shortcut { keys: string[]; label: string; category: string; }
// ShortcutHelp.tsx
import { useState, useMemo } from 'react';
export function ShortcutHelp({ shortcuts, open, onClose }: { shortcuts: ReadonlyArray<Shortcut>; open: boolean; onClose: () => void }) {
  const [query, setQuery] = useState('');
  const filtered = useMemo(() => { const q = query.toLowerCase(); return shortcuts.filter(s => s.label.toLowerCase().includes(q) || s.keys.join('').toLowerCase().includes(q)); }, [shortcuts, query]);
  const grouped = useMemo(() => { const map = new Map<string, Shortcut[]>(); for (const s of filtered) { if (!map.has(s.category)) map.set(s.category, []); map.get(s.category)!.push(s); } return map; }, [filtered]);
