// CursorChat.tsx
import { useEffect, useState } from 'react';
export function CursorChat({ onSend, cursorPos }: { onSend: (msg: string) => void; cursorPos: { x: number; y: number } }) {
  const [input, setInput] = useState<string | null>(null);
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.key === '/' && input === null && !(e.target instanceof HTMLInputElement)) { e.preventDefault(); setInput(''); }
      else if (input !== null) {
        if (e.key === 'Enter') { if (input.trim()) onSend(input.trim()); setInput(null); }
        else if (e.key === 'Escape') { setInput(null); }
      }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [input, onSend]);
  if (input === null) return null;
  return (
    <input autoFocus value={input} onChange={(e) => setInput(e.target.value)} className="fixed bg-[oklch(0.18_0.005_250)] text-white text-[13px] rounded px-2 py-1.5 outline-none ring-2 ring-[oklch(0.55_0.18_250)]" style={{ left: cursorPos.x + 16, top: cursorPos.y + 16, animation: 'chatIn 150ms ease-out' }} placeholder="Type and Enter\u2026" maxLength={80} />
  );
}
// RemoteCursorBubble.tsx
import { useEffect, useState } from 'react';
export function RemoteCursorBubble({ message, userColor, cursorPos }: { message: string; userColor: string; cursorPos: { x: number; y: number } }) {
  const [visible, setVisible] = useState(true);
  useEffect(() => { const t = window.setTimeout(() => setVisible(false), 8000); return () => window.clearTimeout(t); }, [message]);
  if (!visible) return null;
  return (
    <div className="fixed bg-[oklch(0.18_0.005_250)] text-white text-[13px] rounded px-2 py-1.5 border-2 pointer-events-none" style={{ left: cursorPos.x + 16, top: cursorPos.y + 16, borderColor: userColor, animation: 'chatIn 150ms ease-out, chatOut 300ms ease-in 7700ms forwards' }}>{message}
      <style>{`@keyframes chatIn { from { opacity: 0; transform: translateY(-4px) } to { opacity: 1; transform: translateY(0) } } @keyframes chatOut { to { opacity: 0 } }`}</style>
    </div>
  );
}

