// DonutChart.tsx
import { useState } from 'react';
export interface DonutSegment { id: string; label: string; value: number; color: string; }
export function DonutChart({ segments }: { segments: ReadonlyArray<DonutSegment> }) {
  const [hoverId, setHoverId] = useState<string | null>(null);
  const total = segments.reduce((s, x) => s + x.value, 0);
  const R_OUTER = 100, R_INNER = 60, CX = 120, CY = 120;
  let startAngle = -Math.PI / 2;
  const arcs = segments.map(s => { const frac = s.value / total; const endAngle = startAngle + frac * Math.PI * 2; const arc = { id: s.id, label: s.label, value: s.value, color: s.color, startAngle, endAngle, midAngle: (startAngle + endAngle) / 2 }; startAngle = endAngle; return arc; });
  const hoverSeg = hoverId ? arcs.find(a => a.id === hoverId) : null;
  const centerValue = hoverSeg ? hoverSeg.value : total;
  const centerLabel = hoverSeg ? `${hoverSeg.label} (${((hoverSeg.value / total) * 100).toFixed(0)}%)` : 'Total';
  function arcPath(a: typeof arcs[number], offset = 0) {
    const dx = Math.cos(a.midAngle) * offset, dy = Math.sin(a.midAngle) * offset;
    const x1 = CX + dx + Math.cos(a.startAngle) * R_OUTER, y1 = CY + dy + Math.sin(a.startAngle) * R_OUTER;
    const x2 = CX + dx + Math.cos(a.endAngle) * R_OUTER, y2 = CY + dy + Math.sin(a.endAngle) * R_OUTER;
    const x3 = CX + dx + Math.cos(a.endAngle) * R_INNER, y3 = CY + dy + Math.sin(a.endAngle) * R_INNER;
    const x4 = CX + dx + Math.cos(a.startAngle) * R_INNER, y4 = CY + dy + Math.sin(a.startAngle) * R_INNER;
    const large = a.endAngle - a.startAngle > Math.PI ? 1 : 0;
    return `M${x1} ${y1} A${R_OUTER} ${R_OUTER} 0 ${large} 1 ${x2} ${y2} L${x3} ${y3} A${R_INNER} ${R_INNER} 0 ${large} 0 ${x4} ${y4} Z`;
  }
  return (
    <div className="relative" style={{ width: 240, height: 240 }}>
      <svg viewBox="0 0 240 240" className="w-full h-full">{arcs.map(a => <path key={a.id} d={arcPath(a, hoverId === a.id ? 4 : 0)} fill={a.color} onMouseEnter={() => setHoverId(a.id)} onMouseLeave={() => setHoverId(null)} style={{ transition: 'd 200ms ease-out' }} />)}</svg>
      <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
        <div className="text-[32px] tabular-nums font-medium" key={centerValue}>${(centerValue).toLocaleString()}</div>
        <div className="text-[12px] uppercase tracking-wider text-[oklch(0.55_0.005_250)]">{centerLabel}</div>
      </div>
    </div>
  );
}

